mapper.update:
/* com.educare.edu.comn.mapper.FeedbackEduResultMapper.updateByPk */
	update t_feedback_edu_result
	set upd_de = #{updDe} ,upd_id = #{updId}
		,state 		= #{state} 
	where fe_seq = #{feSeq} and user_id = #{userId}

mapper.delete:
/* com.educare.edu.comn.mapper.FeedbackEduResultMapper.deleteByPk */
	delete from t_feedback_edu_result
	where fe_seq = #{feSeq} and user_id = #{userId}

mapper.select:
/* com.educare.edu.comn.mapper.FeedbackEduResultMapper.selectCnt */
	select count(*) from t_feedback_edu_result
	where 1=1
	and edu_seq = #{eduSeq}
	and fe_seq = #{feSeq}

	and state = #{state}
